import{_ as s,o as a,c as i,ak as l}from"./chunks/framework.DwHlt8HN.js";const m=JSON.parse('{"title":"Helm","description":"","frontmatter":{},"headers":[],"relativePath":"devops/k8s/helm/index.md","filePath":"devops/k8s/helm/index.md","lastUpdated":1774320699000}'),n={name:"devops/k8s/helm/index.md"};function t(r,e,p,h,o,d){return a(),i("div",null,[...e[0]||(e[0]=[l(`<h1 id="helm" tabindex="-1">Helm <a class="header-anchor" href="#helm" aria-label="Permalink to “Helm”">​</a></h1><p>Kubernetes 的包管理器，让复杂的应用部署变得简单。</p><p>当你的 Kubernetes 集群里有几十个服务，每个服务都有几十个 YAML 配置文件——Deployment、Service、ConfigMap、Secret、Ingress……手动管理这些配置文件很快就会变成噩梦。Helm 解决的就是这个问题。</p><p>Helm 的核心思想来自 Linux 的包管理器 apt/yum：把一组 Kubernetes 配置文件打包成一个「Chart」，然后用一条命令就能安装、升级、回滚整个应用。它还支持模板化、版本管理、依赖声明，让 Kubernetes 的应用分发变得标准化和可重复。</p><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to “核心概念”">​</a></h2><p>理解 Helm，先理解三个核心概念：</p><p><strong>Chart</strong>：一个 Chart 就是一组 Kubernetes 资源的包。它包含：</p><ul><li><code>Chart.yaml</code>：元数据（名称、版本、依赖等）</li><li><code>values.yaml</code>：默认配置值</li><li><code>templates/</code>：Kubernetes 资源模板文件</li><li><code>charts/</code>：依赖的子 Chart</li></ul><p><strong>Repository</strong>：Chart 的仓库，类似于 Docker Hub。你可以发布自己的 Chart，也可以使用公开的仓库（如 Bitnami、Prometheus 官方 Chart 库）。</p><p><strong>Release</strong>：一个 Release 是 Chart 在集群中的一次安装实例。同一个 Chart 可以安装多个 Release，每个 Release 都有独立的配置和状态。</p><h2 id="为什么需要-helm" tabindex="-1">为什么需要 Helm？ <a class="header-anchor" href="#为什么需要-helm" aria-label="Permalink to “为什么需要 Helm？”">​</a></h2><p>想象一个场景：你要在测试环境和生产环境部署同一个应用，区别仅在于副本数、资源限制、副本名称。</p><p>没有 Helm：你需要维护两套 YAML 文件，或者用脚本在部署前替换占位符。</p><p>有 Helm：你定义一个 <code>values.yaml</code>，然后：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 测试环境</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">helm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-app</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./chart</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> values-test.yaml</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 生产环境</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">helm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-app</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./chart</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> values-prod.yaml</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>一条命令，环境和配置完全隔离。</p><h2 id="面试的核心逻辑" tabindex="-1">面试的核心逻辑 <a class="header-anchor" href="#面试的核心逻辑" aria-label="Permalink to “面试的核心逻辑”">​</a></h2><p>Helm 面试通常考察以下方面：</p><ol><li><strong>概念理解</strong>：Chart、Repository、Release 的关系是什么？Helm 3 和 Helm 2 最大的区别是什么？</li><li><strong>模板语法</strong>：如何在模板中使用条件判断、循环、函数？<code>&amp;#123;&amp;#123; .Values.xxx &amp;#125;&amp;#125;</code> 的点号表示什么？</li><li><strong>进阶用法</strong>：Helm Hook 可以用来做什么？Helmfile 如何管理多环境？</li><li><strong>GitOps 结合</strong>：Helm 如何与 ArgoCD 集成实现声明式部署？</li></ol><blockquote><p>&quot;Helm 的面试，本质上考的是你对 Kubernetes YAML 配置管理的理解深度——理解 Helm 的模板机制，就理解了 Kubernetes 配置声明式的精髓。&quot;</p></blockquote>`,20)])])}const c=s(n,[["render",t]]);export{m as __pageData,c as default};
